/**
 * Buildify365 TOC Widget v1.1.0
 * https://www.buildify365.com
 *
 * 티스토리 블로그 자동 목차(TOC) 위젯
 *
 * 3가지 모드:
 *   1) 인라인 TOC  — 글 상단에 접기/펼치기 목차
 *   2) 사이드 TOC  — 데스크탑에서 사이드 고정 + 스크롤 추적
 *   3) 모바일 FAB  — 모바일에서 플로팅 버튼 + 드로어
 *
 * 사용법 (서식 기반):
 *   1. buildify365.com/ko/widgets/toc 에서 옵션 설정 후 코드 복사
 *   2. 티스토리 > 콘텐츠 > 서식 관리 > 서식 쓰기 > HTML 모드에서 붙여넣기
 *   3. 글 쓸 때 서식 불러오기 → 끝
 *
 * 생성 코드 예시:
 *   <div id="bf-toc" data-mode="all" data-theme="light" data-color="#6366f1"></div>
 *   <script src="https://cdn.jsdelivr.net/gh/buildify365/toc-widget@latest/bf-toc.min.js"></script>
 *
 * 옵션 (<div id="bf-toc"> data 속성):
 *   data-mode="all|inline|sidebar"  표시 모드 (기본: all)
 *   data-theme="light|dark"         테마 (기본: light)
 *   data-color="#6366f1"            메인 색상
 *   data-position="right|left"      사이드 위치 (기본: right)
 *   data-min-headings="3"           최소 헤딩 수 (기본: 3)
 *   data-inline-open="true|false"   인라인 TOC 기본 펼침 (기본: true)
 *   data-sidebar-progress="true|false" 사이드바 진행률 바 (기본: true)
 *
 * MIT License - Copyright (c) 2025 buildify365
 */
(function () {
  'use strict';

  // ============================================================
  // 0. 설정 — <div id="bf-toc"> 에서 data 속성 읽기
  // ============================================================
  var el = document.getElementById('bf-toc');
  if (!el) return;

  var C = {
    mode: el.getAttribute('data-mode') || 'all',
    theme: el.getAttribute('data-theme') || 'light',
    color: el.getAttribute('data-color') || '#6366f1',
    position: el.getAttribute('data-position') || 'right',
    minHeadings: parseInt(el.getAttribute('data-min-headings'), 10) || 3,
    inlineOpen: el.getAttribute('data-inline-open') !== 'false',
    sidebarProgress: el.getAttribute('data-sidebar-progress') !== 'false'
  };

  var showInline = C.mode === 'all' || C.mode === 'inline';
  var showSidebar = C.mode === 'all' || C.mode === 'sidebar';

  // ============================================================
  // 1. 티스토리 본문 찾기
  // ============================================================
  var SELECTORS = [
    '.area_view', '.entry-content', '.article_view',
    '#content .post-content', '.tt_article_useless_p_margin',
    'article .contents_style', '.article-view', 'article'
  ];

  function findContent() {
    for (var i = 0; i < SELECTORS.length; i++) {
      var el = document.querySelector(SELECTORS[i]);
      if (el) return el;
    }
    return null;
  }

  // ============================================================
  // 2. 헤딩 수집
  // ============================================================
  function collectHeadings(el) {
    var hs = el.querySelectorAll('h2,h3,h4'), r = [];
    for (var i = 0; i < hs.length; i++) {
      var h = hs[i], t = (h.textContent || '').replace(/\s+/g, ' ').trim();
      if (!t) continue;
      if (!h.id) h.id = 'bf365-' + i;
      r.push({ id: h.id, text: t, level: parseInt(h.tagName[1], 10) });
    }
    return r;
  }

  // ============================================================
  // 3. 색상 유틸
  // ============================================================
  function rgba(hex, a) {
    hex = hex.replace('#', '');
    if (hex.length === 3) hex = hex[0] + hex[0] + hex[1] + hex[1] + hex[2] + hex[2];
    var n = parseInt(hex, 16);
    return 'rgba(' + ((n >> 16) & 255) + ',' + ((n >> 8) & 255) + ',' + (n & 255) + ',' + a + ')';
  }

  // ============================================================
  // 4. 스타일 주입
  // ============================================================
  function injectStyles() {
    var mc = C.color;
    var dk = C.theme === 'dark';
    var L = C.position === 'left';

    var bg = dk ? '#1a1a1e' : '#ffffff';
    var bg2 = dk ? '#141417' : '#f8f9fb';
    var bd = dk ? '#2a2a30' : '#e4e4e7';
    var bd2 = dk ? '#222228' : '#f4f4f5';
    var tx = dk ? '#d4d4d8' : '#3f3f46';
    var tx2 = dk ? '#e4e4e7' : '#27272a';
    var mt = dk ? '#71717a' : '#a1a1aa';
    var hv = dk ? '#27272a' : '#f4f4f5';
    var dm = dk ? '#52525b' : '#c4c4cc';
    var pw = dk ? '#71717a' : '#a1a1aa';

    var css = '' +

    // ========================
    // 공통 리셋
    // ========================
    '.bf-toc *{margin:0;padding:0;box-sizing:border-box;' +
    'font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,"Noto Sans KR",sans-serif}' +

    // ========================
    // 인라인 TOC
    // ========================
    '.bf-inline{background:' + bg2 + ';border:1px solid ' + bd + ';border-radius:12px;margin-bottom:32px;overflow:hidden}' +

    '.bf-inline-head{width:100%;display:flex;align-items:center;justify-content:space-between;' +
    'padding:12px 16px;background:none;border:none;cursor:pointer;font-size:13px;font-weight:700;color:' + tx2 + '}' +

    '.bf-inline-title{display:flex;align-items:center;gap:7px}' +
    '.bf-inline-title svg{width:14px;height:14px;stroke:' + mc + ';flex-shrink:0}' +
    '.bf-inline-count{font-size:11px;font-weight:500;color:' + mt + '}' +

    '.bf-inline-arrow{width:16px;height:16px;stroke:' + mt + ';transition:transform .2s}' +
    '.bf-inline-arrow.bf-open{transform:rotate(180deg)}' +

    '.bf-inline-body{overflow:hidden;transition:max-height .3s ease}' +

    '.bf-inline-list{list-style:none;padding:0 0 10px;margin:0}' +

    '.bf-inline-list a{display:flex;align-items:center;gap:6px;text-decoration:none;cursor:pointer;' +
    'line-height:1.6;transition:color .15s}' +
    '.bf-inline-list a:hover{color:' + mc + '!important}' +

    '.bf-inline-list .bf-il2{padding:3px 16px 3px 20px;font-size:13px;font-weight:600;color:' + tx2 + '}' +
    '.bf-inline-list .bf-il3{padding:3px 16px 3px 36px;font-size:12px;font-weight:400;color:' + mt + '}' +
    '.bf-inline-list .bf-il4{padding:3px 16px 3px 50px;font-size:11px;font-weight:400;color:' + dm + '}' +

    '.bf-inline-dot2{font-size:10px;opacity:.5}' +
    '.bf-inline-dot3{font-size:8px;opacity:.5}' +

    // ========================
    // 사이드 TOC
    // ========================
    '.bf-side{position:fixed;top:50%;transform:translateY(-50%);' +
    (L ? 'left:20px;' : 'right:20px;') +
    'width:240px;max-height:70vh;background:' + bg + ';border:1px solid ' + bd + ';' +
    'border-radius:14px;box-shadow:0 1px 3px rgba(0,0,0,.04),0 4px 16px rgba(0,0,0,.06);' +
    'z-index:9990;overflow:hidden;display:flex;flex-direction:column}' +

    '.bf-side-head{display:flex;align-items:center;gap:7px;padding:14px 16px 10px;' +
    'border-bottom:1px solid ' + bd2 + ';font-size:10px;font-weight:700;letter-spacing:1px;' +
    'text-transform:uppercase;color:' + mt + ';flex-shrink:0}' +
    '.bf-side-head svg{width:13px;height:13px;stroke:' + mc + ';flex-shrink:0}' +

    '.bf-side-list{list-style:none;padding:6px 0;margin:0;overflow-y:auto;flex:1}' +
    '.bf-side-list::-webkit-scrollbar{width:3px}' +
    '.bf-side-list::-webkit-scrollbar-thumb{background:' + bd + ';border-radius:3px}' +

    '.bf-side-list a{display:block;text-decoration:none;font-size:12px;font-weight:500;line-height:1.4;' +
    'color:' + tx + ';padding:4px 16px;border-left:2.5px solid transparent;transition:all .15s;cursor:pointer;word-break:keep-all}' +
    '.bf-side-list a:hover{background:' + hv + ';color:' + (dk ? '#fff' : '#18181b') + '}' +
    '.bf-side-list a.bf-on{color:' + mc + ';background:' + rgba(mc, .06) + ';border-left-color:' + mc + ';font-weight:600}' +

    '.bf-side-list a.bf-l3{padding-left:30px;font-size:11px;font-weight:400;color:' + mt + '}' +
    '.bf-side-list a.bf-l3.bf-on{color:' + mc + ';font-weight:500}' +
    '.bf-side-list a.bf-l3:hover{color:' + tx + '}' +
    '.bf-side-list a.bf-l4{padding-left:42px;font-size:10.5px;font-weight:400;color:' + dm + '}' +
    '.bf-side-list a.bf-l4.bf-on{color:' + mc + '}' +

    // Progress
    '.bf-prog{display:flex;align-items:center;gap:6px;padding:8px 16px;border-top:1px solid ' + bd2 + ';flex-shrink:0}' +
    '.bf-pct{font-size:9px;font-weight:600;color:' + mt + ';min-width:26px}' +
    '.bf-bar{flex:1;height:2.5px;background:' + bd2 + ';border-radius:3px;overflow:hidden}' +
    '.bf-fill{height:100%;width:0%;background:linear-gradient(90deg,' + mc + ',' + rgba(mc, .6) + ');border-radius:3px;transition:width .3s}' +

    // Powered by
    '.bf-pw{display:flex;align-items:center;justify-content:center;gap:4px;padding:7px 16px 10px;' +
    'border-top:1px solid ' + bd2 + ';text-decoration:none;flex-shrink:0;transition:opacity .2s}' +
    '.bf-pw:hover{opacity:.6}' +
    '.bf-pw span{font-size:8.5px;font-weight:500;color:' + dm + '}' +
    '.bf-pw strong{font-size:8.5px;font-weight:700;color:' + pw + '}' +

    // 인라인용 pw
    '.bf-pw-inline{display:flex;justify-content:flex-end;align-items:center;gap:4px;' +
    'padding:8px 16px;border-top:1px solid ' + bd + ';text-decoration:none;transition:opacity .2s}' +
    '.bf-pw-inline:hover{opacity:.6}' +
    '.bf-pw-inline span{font-size:9px;font-weight:500;color:' + dm + '}' +
    '.bf-pw-inline strong{font-size:9px;font-weight:700;color:' + pw + '}' +

    // ========================
    // FAB + Drawer
    // ========================
    '.bf-fab{display:none;position:fixed;bottom:20px;' + (L ? 'left:20px;' : 'right:20px;') +
    'width:46px;height:46px;border-radius:50%;background:' + mc + ';color:#fff;border:none;cursor:pointer;' +
    'z-index:9992;box-shadow:0 4px 16px ' + rgba(mc, .35) + ';transition:all .2s;align-items:center;justify-content:center}' +
    '.bf-fab:hover{transform:scale(1.08)}' +
    '.bf-fab svg{width:20px;height:20px}' +
    '.bf-fab .bf-ic2{display:none}' +
    '.bf-fab.bf-open .bf-ic1{display:none}' +
    '.bf-fab.bf-open .bf-ic2{display:block}' +

    '.bf-drawer{display:none;position:fixed;bottom:78px;' + (L ? 'left:20px;' : 'right:20px;') +
    'width:270px;max-height:60vh;background:' + bg + ';border:1px solid ' + bd + ';border-radius:14px;' +
    'box-shadow:0 8px 32px rgba(0,0,0,.12);z-index:9991;overflow:hidden;flex-direction:column;' +
    'opacity:0;transform:translateY(10px) scale(.96);' +
    'transition:all .25s cubic-bezier(.4,0,.2,1);pointer-events:none}' +
    '.bf-drawer.bf-open{opacity:1;transform:translateY(0) scale(1);pointer-events:auto}' +
    '.bf-drawer .bf-side-list a{font-size:12.5px;padding:5px 16px}' +
    '.bf-drawer .bf-side-list a.bf-l3{padding-left:30px}' +
    '.bf-drawer .bf-side-list a.bf-l4{padding-left:42px}' +

    '.bf-ov{display:none;position:fixed;inset:0;background:rgba(0,0,0,.1);z-index:9989;opacity:0;transition:opacity .25s}' +
    '.bf-ov.bf-open{opacity:1}' +

    // ========================
    // 반응형
    // ========================
    '@media(max-width:1340px){' +
      '.bf-side{display:none!important}' +
      '.bf-fab{display:flex}' +
      '.bf-drawer{display:flex}' +
    '}';

    var s = document.createElement('style');
    s.id = 'bf365-toc-css';
    s.textContent = css;
    document.head.appendChild(s);
  }

  // ============================================================
  // 5. SVG 아이콘
  // ============================================================
  var IC_TOC = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M4 6h16M4 12h16M4 18h7"/></svg>';
  var IC_ARROW = '<svg class="bf-inline-arrow' + (C.inlineOpen ? ' bf-open' : '') + '" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M6 9l6 6 6-6"/></svg>';
  var IC_MENU = '<svg class="bf-ic1" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M4 6h16M4 12h16M4 18h7"/></svg>';
  var IC_CLOSE = '<svg class="bf-ic2" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M18 6L6 18M6 6l12 12"/></svg>';

  var PW_LINK = 'https://www.buildify365.com/ko/widgets/toc?ref=widget';

  function pwHTML(cls) {
    return '<a href="' + PW_LINK + '" target="_blank" rel="noopener" class="' + cls + '">' +
      '<span>powered by</span> <strong>buildify365</strong></a>';
  }

  // ============================================================
  // 6. 인라인 TOC 생성
  // ============================================================
  function createInlineTOC(headings, contentEl) {
    var sectionCount = 0;
    for (var i = 0; i < headings.length; i++) { if (headings[i].level === 2) sectionCount++; }

    var listHTML = '';
    for (var j = 0; j < headings.length; j++) {
      var h = headings[j];
      var cls = 'bf-il' + h.level;
      var dot = h.level === 2 ? '<span class="bf-inline-dot2">▸</span>' :
                h.level === 3 ? '<span class="bf-inline-dot3">∘</span>' :
                '<span class="bf-inline-dot3">·</span>';
      listHTML += '<li><a href="#' + h.id + '" class="' + cls + '">' + dot + h.text + '</a></li>';
    }

    var el = document.createElement('div');
    el.className = 'bf-toc bf-inline';
    el.innerHTML = '' +
      '<button class="bf-inline-head" type="button">' +
        '<span class="bf-inline-title">' + IC_TOC +
          '목차 <span class="bf-inline-count">(' + sectionCount + '개 섹션)</span>' +
        '</span>' +
        IC_ARROW +
      '</button>' +
      '<div class="bf-inline-body" style="max-height:' + (C.inlineOpen ? '800px' : '0') + '">' +
        '<ul class="bf-inline-list">' + listHTML + '</ul>' +
        pwHTML('bf-pw-inline') +
      '</div>';

    // 본문 맨 앞에 삽입 (첫번째 h2 앞)
    var firstH2 = contentEl.querySelector('h2');
    if (firstH2) {
      contentEl.insertBefore(el, firstH2);
    } else {
      contentEl.insertBefore(el, contentEl.firstChild);
    }

    // 토글
    var btn = el.querySelector('.bf-inline-head');
    var body = el.querySelector('.bf-inline-body');
    var arrow = el.querySelector('.bf-inline-arrow');
    var isOpen = C.inlineOpen;

    btn.addEventListener('click', function () {
      isOpen = !isOpen;
      body.style.maxHeight = isOpen ? '800px' : '0';
      if (isOpen) arrow.classList.add('bf-open');
      else arrow.classList.remove('bf-open');
    });

    return el;
  }

  // ============================================================
  // 7. 사이드/드로어 TOC HTML
  // ============================================================
  function sideListHTML(headings) {
    var html = '';
    for (var i = 0; i < headings.length; i++) {
      var h = headings[i];
      var cls = h.level === 3 ? ' bf-l3' : h.level === 4 ? ' bf-l4' : '';
      html += '<li><a href="#' + h.id + '" class="' + cls + '">' + h.text + '</a></li>';
    }
    return '' +
      '<div class="bf-side-head">' + IC_TOC + '목차</div>' +
      '<ul class="bf-side-list">' + html + '</ul>' +
      (C.sidebarProgress ? '<div class="bf-prog"><span class="bf-pct">0%</span><div class="bf-bar"><div class="bf-fill"></div></div></div>' : '') +
      pwHTML('bf-pw');
  }

  function createSidebar(headings) {
    var el = document.createElement('nav');
    el.className = 'bf-toc bf-side';
    el.setAttribute('aria-label', '목차');
    el.innerHTML = sideListHTML(headings);
    document.body.appendChild(el);
    return el;
  }

  function createFAB() {
    var el = document.createElement('button');
    el.className = 'bf-toc bf-fab';
    el.setAttribute('aria-label', '목차');
    el.innerHTML = IC_MENU + IC_CLOSE;
    document.body.appendChild(el);
    return el;
  }

  function createDrawer(headings) {
    var el = document.createElement('div');
    el.className = 'bf-toc bf-drawer';
    el.innerHTML = sideListHTML(headings);
    document.body.appendChild(el);
    return el;
  }

  function createOverlay() {
    var el = document.createElement('div');
    el.className = 'bf-ov';
    document.body.appendChild(el);
    return el;
  }

  // ============================================================
  // 8. 인터랙션
  // ============================================================
  function bindAll(sidebar, fab, drawer, overlay, inlineEl, headings) {

    // --- Smooth scroll ---
    function scrollToId(id) {
      var target = document.getElementById(id);
      if (target) {
        var y = target.getBoundingClientRect().top + window.pageYOffset - 20;
        window.scrollTo({ top: y, behavior: 'smooth' });
      }
    }

    function onLink(e) {
      var a = e.target.closest('a[href^="#"]');
      if (!a) return;
      var href = a.getAttribute('href');
      if (!href || href.length < 2) return;
      e.preventDefault();
      scrollToId(href.substring(1));
      closeDrawer();
    }

    if (sidebar) sidebar.addEventListener('click', onLink);
    if (drawer) drawer.addEventListener('click', onLink);
    if (inlineEl) inlineEl.addEventListener('click', onLink);

    // --- Mobile drawer ---
    var isOpen = false;

    function openDrawer() {
      if (!fab || !drawer || !overlay) return;
      isOpen = true;
      fab.classList.add('bf-open');
      drawer.classList.add('bf-open');
      overlay.style.display = 'block';
      overlay.offsetHeight;
      overlay.classList.add('bf-open');
    }

    function closeDrawer() {
      if (!isOpen || !fab) return;
      isOpen = false;
      fab.classList.remove('bf-open');
      if (drawer) drawer.classList.remove('bf-open');
      if (overlay) {
        overlay.classList.remove('bf-open');
        setTimeout(function () { overlay.style.display = 'none'; }, 250);
      }
    }

    if (fab) {
      fab.addEventListener('click', function () {
        if (isOpen) closeDrawer(); else openDrawer();
      });
    }
    if (overlay) overlay.addEventListener('click', closeDrawer);

    // --- Scroll tracking (sidebar & drawer) ---
    if (!sidebar && !drawer) return;

    var headingEls = [];
    for (var i = 0; i < headings.length; i++) {
      var el = document.getElementById(headings[i].id);
      if (el) headingEls.push(el);
    }

    var curId = null;
    function setActive(id) {
      if (id === curId) return;
      curId = id;
      var all = document.querySelectorAll('.bf-side-list a');
      for (var i = 0; i < all.length; i++) {
        var a = all[i];
        var match = a.getAttribute('href') === '#' + id;
        if (match) {
          a.classList.add('bf-on');
          var list = a.closest('.bf-side-list');
          if (list) {
            var lt = a.offsetTop - list.offsetTop;
            if (lt < list.scrollTop || lt > list.scrollTop + list.clientHeight - 30) {
              list.scrollTop = lt - list.clientHeight / 3;
            }
          }
        } else {
          a.classList.remove('bf-on');
        }
      }
    }

    if ('IntersectionObserver' in window) {
      var obs = new IntersectionObserver(function (entries) {
        for (var i = 0; i < entries.length; i++) {
          if (entries[i].isIntersecting) setActive(entries[i].target.id);
        }
      }, { rootMargin: '0px 0px -70% 0px' });
      for (var j = 0; j < headingEls.length; j++) obs.observe(headingEls[j]);
    }

    // --- Progress ---
    function updateProgress() {
      var st = window.pageYOffset || document.documentElement.scrollTop;
      var dh = document.documentElement.scrollHeight - window.innerHeight;
      var p = dh > 0 ? Math.min(Math.round((st / dh) * 100), 100) : 0;
      var fills = document.querySelectorAll('.bf-fill');
      var pcts = document.querySelectorAll('.bf-pct');
      for (var i = 0; i < fills.length; i++) fills[i].style.width = p + '%';
      for (var k = 0; k < pcts.length; k++) pcts[k].textContent = p + '%';
    }

    var timer = null;
    window.addEventListener('scroll', function () {
      if (timer) return;
      timer = setTimeout(function () { timer = null; updateProgress(); }, 30);
    }, { passive: true });
    updateProgress();
  }

  // ============================================================
  // 9. 초기화
  // ============================================================
  function init() {
    var contentEl = findContent();
    if (!contentEl) return;

    var headings = collectHeadings(contentEl);
    if (headings.length < C.minHeadings) return;

    injectStyles();

    var inlineEl = null;
    var sidebar = null;
    var fab = null;
    var drawer = null;
    var overlay = null;

    // 인라인 TOC
    if (showInline) {
      inlineEl = createInlineTOC(headings, contentEl);
    }

    // 사이드 TOC + 모바일
    if (showSidebar) {
      sidebar = createSidebar(headings);
      fab = createFAB();
      drawer = createDrawer(headings);
      overlay = createOverlay();
    }

    bindAll(sidebar, fab, drawer, overlay, inlineEl, headings);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

})();
